import { createLinterRuleTester, LinterRuleTester } from "@typespec/compiler/testing";
import { beforeEach, describe, it } from "vitest";
import { Tester } from "../testing/test-host.js";
import { sdkOperationsNamespaceRule } from "./sdk-operations-namespace.rule.js";

// a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.rule_sdk_operations_namespace
describe("sdk-operations-namespace rule", () => {
  let ruleTester: LinterRuleTester;

  beforeEach(async () => {
    const runner = await Tester.createInstance();
    ruleTester = createLinterRuleTester(runner, sdkOperationsNamespaceRule, "@a10n/blueprint-typespec");
  });

  // ─── valid ────────────────────────────────────────────────────────────────

  describe("valid", () => {
    // a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.rule_sdk_operations_namespace
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T009.T009_01
    it("Sdk op inside namespace Operations passes", async () => {
      await ruleTester
        .expect(`
          @component(#{ type: ComponentType.Sdk })
          namespace Components.MyTaskManagerEmitterSdk {
            namespace Operations {
              @operation(#{})
              op dispatch(): void;
            }
          }
        `)
        .toBeValid();
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T009.T009_02
    it("non-Sdk component op is ignored", async () => {
      await ruleTester
        .expect(`
          @component(#{ type: ComponentType.Service })
          namespace Components.MyApiService {
            @operation(#{})
            op flat_op(): void;
          }
        `)
        .toBeValid();
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T009.T009_03
    it("op without @operation inside Sdk component is ignored", async () => {
      await ruleTester
        .expect(`
          @component(#{ type: ComponentType.Sdk })
          namespace Components.MySdk {
            op bare_op(): void;
          }
        `)
        .toBeValid();
    });
  });

  // ─── invalid ──────────────────────────────────────────────────────────────

  describe("invalid", () => {
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T009.T009_04
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_sdk_operations_namespace:Products.A10nBlueprintEngine.Features.InterfaceNamespacePlacement.sdk_operations_namespace:must
    it("flat @operation in Sdk component emits warning", async () => {
      await ruleTester
        .expect(`
          @component(#{ type: ComponentType.Sdk })
          namespace Components.MyAgentDispatcherSdk {
            @operation(#{})
            op dispatch(): void;
          }
        `)
        .toEmitDiagnostics({
          code: "@a10n/blueprint-typespec/sdk-operations-namespace",
          message: /dispatch/,
        });
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T009.T009_05
    it("message includes the operation FQN", async () => {
      await ruleTester
        .expect(`
          @component(#{ type: ComponentType.Sdk })
          namespace Components.MyAgentDispatcherSdk {
            @operation(#{})
            op dispatch(): void;
          }
        `)
        .toEmitDiagnostics({
          code: "@a10n/blueprint-typespec/sdk-operations-namespace",
          message: /Components\.MyAgentDispatcherSdk\.dispatch/,
        });
    });
  });
});
